recommendations.code:
add_header X-Content-Type-Options "nosniff" always;
add_header X-Frame-Options "DENY" always;
add_header Referrer-Policy "strict-origin-when-cross-origin" always;
add_header Permissions-Policy "accelerometer=(), camera=(), geolocation=(), gyroscope=(), microphone=(), payment=(), usb=()" always;

server {
    listen 80;
    server_name explore21.com www.explore21.com;
    return 301 https://$host$request_uri;
}

server {
    listen 443 ssl http2;
    server_name www.explore21.com;
    return 301 https://explore21.com$request_uri;
}

location ~ \.(js|css|woff2|png|svg)$ {
    add_header Cache-Control "public, max-age=31536000, immutable" always;
}
